class Solution:
    def addOperators(self, num: str, target: int) -> List[str]:
        def dfs(index, path, value, last):
            if index == len(num) and value == target:
                result.append(path)
                return
            for i in range(index + 1, len(num) + 1):
                if i > index + 1 and num[index] == "0":
                    break
                num_str = num[index:i]
                num_val = int(num_str)
                if index == 0:
                    dfs(i, num_str, num_val, num_val)
                else:
                    dfs(i, path + "+" + num_str, value + num_val, num_val)
                    dfs(i, path + "-" + num_str, value - num_val, -num_val)
                    dfs(i, path + "*" + num_str, value - last + last * num_val, last * num_val)

        result = []
        dfs(0, "", 0, 0)
        return result

