class Solution(object):
    def countRangeSum(self, nums, lower, upper):
        """
        :type nums: List[int]
        :type lower: int
        :type upper: int
        :rtype: int
        """
        def merge_sort(arr, l, r):
            if l >= r:
                return 0
            mid = (l + r) // 2
            count = merge_sort(arr, l, mid) + merge_sort(arr, mid+1, r)
            i, j = mid+1, mid+1
            for left in arr[l:mid+1]:
                while i <= r and arr[i] - left < lower:
                    i += 1
                while j <= r and arr[j] - left <= upper:
                    j += 1
                count += j - i
            arr[l:r+1] = sorted(arr[l:r+1])
            return count
        return merge_sort([0] + nums, 0, len(nums)-1)

