def removeInvalidParentheses(s):
    def is_valid(s):
        count = 0
        for c in s:
            if c == '(':
                count += 1
            elif c == ')':
                count -= 1
                if count < 0:
                    return False
        return count == 0

    def remove_invalid(s):
        queue = deque([s])
        visited = {s}
        found = False
        result = []
        while queue:
            cur = queue.popleft()
            if is_valid(cur):
                found = True
                result.append(cur)
            if found:
                continue
            for i in range(len(cur)):
                if cur[i] in ('(', ')'):
                    next_s = cur[:i] + cur[i+1:]
                    if next_s not in visited:
                        visited.add(next_s)
                        queue.append(next_s)
        return result

    return remove_invalid(s)

