import heapq

class Solution(object):
    def medianSlidingWindow(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: List[float]
        """
        if k == 1:
            return [float(num) for num in nums]
        min_heap = []
        max_heap = []
        result = []
        for i in range(k):
            heapq.heappush(max_heap, (-nums[i], i))
        for _ in range(k // 2):
            heapq.heappush(min_heap, -heapq.heappop(max_heap)[0])
        result.append(self.get_median(min_heap, max_heap, k))
        for i in range(k, len(nums)):
            if nums[i] > -max_heap[0][0]:
                heapq.heappush(min_heap, nums[i])
                if nums[i - k] <= -max_heap[0][0]:
                    heapq.heappush(max_heap, (-min_heap[0], i - k))
                    heapq.heappop(min_heap)
            else:
                heapq.heappush(max_heap, (-nums[i], i))
                if nums[i - k] >= -max_heap[0][0]:
                    heapq.heappush(min_heap, -max_heap[0][0])
                    heapq.heappop(max_heap)
            while max_heap and max_heap[0][1] <= i - k:
                heapq.heappop(max_heap)
            while min_heap and min_heap[0] <= i - k:
                heapq.heappop(min_heap)
            result.append(self.get_median(min_heap, max_heap, k))
        return result

    def get_median(self, min_heap, max_heap, k):
