class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        """
        :type edges: List[List[int]]
        :rtype: List[int]
        """
        parent = {}
        candidates = []
        for edge in edges:
            if edge[1] in parent:
                candidates.append([parent[edge[1]], edge[1]])
                candidates.append(edge)
            else:
                parent[edge[1]] = edge[0]
        def find(x):
            if x not in parent:
                return x
            parent[x] = find(parent[x])
            return parent[x]
        def union(x, y):
            rootX = find(x)
            rootY = find(y)
            if rootX == rootY:
                return False
            parent[rootX] = rootY
            return True
        for edge in edges:
            if not union(edge[0], edge[1]):
                if candidates:
                    return candidates[0]
                else:
                    return edge
        return candidates[1]

