class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)

        @lru_cache(None)
        def dp(r1, c1, r2, c2):
            if r1 == n or c1 == n or r2 == n or c2 == n or grid[r1][c1] == -1 or grid[r2][c2] == -1:
                return float('-inf')
            if r1 == c1 == n - 1:
                return grid[r1][c1]
            cherries = 0
            if r1 == r2 and c1 == c2:
                cherries = grid[r1][c1]
            else:
                cherries = grid[r1][c1] + grid[r2][c2]
            return cherries + max(dp(r1 + 1, c1, r2 + 1, c2), dp(r1, c1 + 1, r2, c2 + 1), dp(r1 + 1, c1, r2, c2 + 1), dp(r1, c1 + 1, r2 + 1, c2))

        result = dp(0, 0, 0, 0)
        return result if result != float('-inf') else 0

