class Solution(object):
    def canCross(self, stones):
        """
        :type stones: List[int]
        :rtype: bool
        """
        if stones[1] != 1:
            return False
        if len(stones) == 2:
            return True

        stone_map = defaultdict(set)
        for stone in stones:
            stone_map[stone] = set()

        stone_map[1].add(1)

        for stone in stones[1:]:
            for step in stone_map[stone]:
                if step - 1 > 0 and stone + step - 1 in stone_map:
                    stone_map[stone + step - 1].add(step - 1)
                if step in stone_map:
