        """
        :type root: TreeNode
        :rtype: List[int]
        """
        if not root:
            return []

        count = {}
        max_count = 0
        stack = [root]

        while stack:
            node = stack.pop()
            if node.val in count:
                count[node.val] += 1
            else:
                count[node.val] = 1
            max_count = max(max_count, count[node.val])

            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)

        modes = [k for k, v in count.items() if v == max_count]

        return modes

