class Solution(object):
    def findAllConcatenatedWordsInADict(self, words):
        """
        :type words: List[str]
        :rtype: List[str]
        """
        words = sorted(words, key=len)
        word_set = set()
        result = []

        def dfs(word):
            if word in word_set:
                return True
            for i in range(1, len(word)):
                prefix, suffix = word[:i], word[i:]
                if prefix in word_set and dfs(suffix):
                    return True
            return False

        for word in words:
            if dfs(word):
                result.append(word)
            word_set.add(word)

        return result

